record.field:
{
  "assistant_name": {
    "type": "string",
    "description": "The name of the assistant (e.g., 'Ody', 'Chuky', 'Ultron')",
    "required": false
  },
  "role": {
    "type": "string",
    "description": "The role of the assistant (e.g., 'Assistant', 'Customer Support', 'Data Analyst')",
    "required": true
  },
  "goal": {
    "type": "string",
    "description": "The primary goal or objective of this assistant",
    "required": true
  },
  "background": {
    "type": "string",
    "description": "Background information for the assistant to understand its context",
    "required": true
  },
  "instructions": {
    "type": "string",
    "description": "Specific instructions for the assistant to follow",
    "required": true
  },
  "user_language": {
    "type": "string",
    "description": "The user's preferred language code (e.g., 'en_US', 'fr_FR')",
    "required": false,
    "default": "en_US"
  },
  "footer": {
    "type": "string",
    "description": "Optional footer text to add to the end of the prompt",
    "required": false,
    "default": ""
  },
  "examples": {
    "type": "object",
    "description": "Optional examples to learn how to answer",
    "required": false
  }
}

